# ============================================================================
# PRIMITIVE HELPER - Bridges seed_primitives into gameplay decisions
# ============================================================================
class PrimitiveHelper:
    """
    Provides easy access to baby-derived cognitive primitives during gameplay.
    
    Wraps the seed_primitives registry to provide perception, attention, 
    and metacognition capabilities for decision-making.
    """
    
    def __init__(self):
        """Initialize primitive helper with seed primitives registry."""
        self._registry: Optional[Any] = None
        self._initialized = False
        
        if PRIMITIVES_AVAILABLE and get_seed_primitives:
            try:
                self._registry = get_seed_primitives()
                self._initialized = True
                logger.debug("[PRIMITIVES] Primitive helper initialized with seed primitives")
            except Exception as e:
                logger.warning(f"[PRIMITIVES] Failed to initialize: {e}")
    
    @property
    def available(self) -> bool:
        """Check if primitives are available."""
        return self._initialized and self._registry is not None
    
    def analyze_frame_changes(
        self,
        frame_before: List,
        frame_after: List
    ) -> Dict[str, Any]:
        """
        Use attention primitives to analyze what changed between frames.
        
        Returns:
            Dict with change detection, motion, and attention guidance
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False}
        
        try:
            changes = registry.call('detect_change', frame_before, frame_after)
            motion = registry.call('detect_motion', frame_before, frame_after)
            
            return {
                'available': True,
                'changed_positions': changes or [],
                'moving_objects': motion or [],
                'has_changes': bool(changes),
                'has_motion': bool(motion)
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Frame analysis failed: {e}")
            return {'available': False, 'error': str(e)}
    
    def check_stuck(
        self,
        score_history: List[float],
        action_history: List[int]
    ) -> Dict[str, Any]:
        """
        Use metacognition primitives to detect if agent is stuck.
        
        Returns:
            Dict with stuck detection and suggestions
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'stuck': False, 'available': False}
        
        try:
            is_stuck = registry.call('detect_stuck', score_history, action_history)
            
            return {
                'available': True,
                'stuck': bool(is_stuck),
                'score_stagnant': len(set(score_history[-5:])) <= 1 if len(score_history) >= 5 else False,
                'action_repeating': len(set(action_history[-10:])) <= 2 if len(action_history) >= 10 else False
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Stuck detection failed: {e}")
            return {'stuck': False, 'available': False, 'error': str(e)}
    
    def analyze_action_contingency(
        self,
        action: int,
        frame_before: List,
        frame_after: List
    ) -> Dict[str, Any]:
        """
        Use attention primitives to check if action caused observable effect.
        
        Returns:
            Dict with contingency detection (did action cause change?)
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'contingent': False, 'available': False}
        
        try:
            contingency = registry.call('detect_contingency', action, frame_before, frame_after)
            
            return {
                'available': True,
                'contingent': bool(contingency.get('contingent', False)) if isinstance(contingency, dict) else bool(contingency),
                'details': contingency if isinstance(contingency, dict) else {}
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Contingency detection failed: {e}")
            return {'contingent': False, 'available': False, 'error': str(e)}
    
    def get_novelty_bonus(
        self,
        current_state: str,
        state_history: List[str]
    ) -> float:
        """
        Use motivation primitives to calculate novelty bonus for exploration.
        
        Returns:
            Float bonus value (0.0 to 1.0)
        """
        registry = self._registry
        if not self.available or registry is None:
            return 0.5  # Default neutral
        
        try:
            bonus = registry.call('novelty_bonus', current_state, state_history)
            return float(bonus) if bonus is not None else 0.5
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Novelty bonus failed: {e}")
            return 0.5
    
    def classify_object_affordance(
        self,
        object_id: str,
        frame: List,
        movement_history: Optional[List] = None
    ) -> Dict[str, Any]:
        """
        Use affordance primitives to classify what an object is for.
        
        Returns:
            Dict with affordance classification
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False}
        
        try:
            is_movable = registry.call('is_movable', object_id, movement_history or [])
            is_obstacle = registry.call('is_obstacle', object_id, frame)
            is_interactive = registry.call('is_interactive', object_id, [])  # Needs interaction history
            is_container = registry.call('is_container', object_id, frame)
            
            return {
                'available': True,
                'object_id': object_id,
                'is_movable': bool(is_movable),
                'is_obstacle': bool(is_obstacle),
                'is_interactive': bool(is_interactive),
                'is_container': bool(is_container)
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Affordance classification failed: {e}")
            return {'available': False, 'error': str(e)}
    
    def detect_negative_space(
        self,
        frame: List
    ) -> Dict[str, Any]:
        """
        Use negative space primitives to detect holes, open edges, and absences.
        Critical for SP80-type water physics games.
        
        Returns:
            Dict with negative space detection results
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False}
        
        try:
            enclosed = registry.call('detect_enclosed_empty', frame)
            open_edges = registry.call('detect_open_edge', frame)
            
            return {
                'available': True,
                'enclosed_regions': enclosed or [],
                'open_edges': open_edges or [],
                'has_containers': bool(enclosed),
                'has_open_edges': bool(open_edges)
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] Negative space detection failed: {e}")
            return {'available': False, 'error': str(e)}

    # ========================================================================
    # NEW PRIMITIVES (2025-01-08): Expanding from 10% to 50%+ usage
    # ========================================================================
    
    def find_all_interactable(self, frame: List) -> Dict[str, Any]:
        """
        Use object interaction primitives to find all clickable/interactable objects.
        Critical for ft09-type games where clicking tiles is the mechanic.
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False, 'objects': []}
        
        try:
            interactables = registry.call('find_all_interactable_objects', frame)
            return {
                'available': True,
                'objects': interactables or [],
                'count': len(interactables) if interactables else 0
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] find_all_interactable failed: {e}")
            return {'available': False, 'objects': [], 'error': str(e)}

    def find_similar(self, reference_obj: Any, frame: List, criteria: str = 'color') -> Dict[str, Any]:
        """
        Find all objects similar to a reference object.
        Critical for symmetry testing - "if this tile toggles, do all same-colored tiles toggle?"
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False, 'similar': []}
        
        try:
            similar = registry.call('find_similar_objects', reference_obj, frame, criteria)
            return {
                'available': True,
                'similar': similar or [],
                'count': len(similar) if similar else 0,
                'criteria': criteria
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] find_similar failed: {e}")
            return {'available': False, 'similar': [], 'error': str(e)}

    def test_object_control(self, object_id: str, action: int, frame_before: List, frame_after: List) -> Dict[str, Any]:
        """
        Test if an action caused a specific object to respond.
        Returns whether the object moved/changed and how.
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False, 'controlled': False}
        
        try:
            result = registry.call('test_object_control', object_id, action, frame_before, frame_after)
            if isinstance(result, dict):
                return {'available': True, **result}
            return {
                'available': True,
                'controlled': bool(result),
                'object_id': object_id,
                'action': action
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] test_object_control failed: {e}")
            return {'available': False, 'controlled': False, 'error': str(e)}

    def detect_click_effect(self, click_pos: Tuple[int, int], frame_before: List, frame_after: List) -> Dict[str, Any]:
        """
        Detect what effect a click had at a specific position.
        Returns toggle/transform/move information.
        """
        registry = self._registry
        if not self.available or registry is None:
            return {'available': False, 'effect': None}
        
        try:
            effect = registry.call('detect_click_effect', click_pos, frame_before, frame_after)
            if isinstance(effect, dict):
                return {'available': True, **effect}
            return {
                'available': True,
                'effect': effect,
                'click_pos': click_pos
            }
        except Exception as e:
            logger.debug(f"[PRIMITIVES] detect_click_effect failed: {e}")
            return {'available': False, 'effect': None, 'error': str(e)}

