class SpineEmitter:
    """Thin helper to write attempt/action events into the spine tables."""

    _ALLOWED_MODES = {'LIVE', 'REPLAY_VALIDATION', 'EVAL', 'LEGACY'}

    def __init__(self, db: DatabaseInterface):
        self.db = db

    def _stack_hash(self, message: str) -> str:
        """Compute a short, stable hash for grouping hook failures."""
        try:
            return hashlib.sha256(message.encode("utf-8", "ignore")).hexdigest()[:12]
        except Exception:
            return message[:64]

    def _validate_mode(self, mode: Optional[str]) -> str:
        """Normalize and validate mode; fall back to LEGACY when absent."""
        normalized = (mode or 'LEGACY').upper()
        if normalized not in self._ALLOWED_MODES:
            raise ValueError(f"Invalid mode '{mode}' supplied to spine write")
        return normalized

    def record_attempt_start(
        self,
        *,
        attempt_id: str,
        game_id: str,
        level: Optional[int],
        agent_id: Optional[str],
        role: str,
        mode: str,
        generation: Optional[int],
        actions_budget: Optional[int],
        game_actions_budget: Optional[int],
        w_A: Optional[float],
        w_B: Optional[float],
        w_R: Optional[float],
        scorecard_id: Optional[str],
    ) -> None:
        self.db.execute_query(
            """
            INSERT OR IGNORE INTO attempts (
              attempt_id, game_id, level, agent_id, role, mode, generation,
              actions_budget, game_actions_budget, w_A_weight, w_B_weight, w_R_weight,
              scorecard_id, guard_budget_ok, guard_role_ok, guard_mode_ok
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, 1, 1, 1)
            """,
            (
                attempt_id,
                game_id,
                level,
                agent_id,
                role,
                self._validate_mode(mode),
                generation,
                actions_budget,
                game_actions_budget,
                w_A,
                w_B,
                w_R,
                scorecard_id,
            ),
        )

    def record_attempt_end(
        self,
        *,
        attempt_id: str,
        actions_used: int,
        game_actions_used: int,
        levels_completed: int,
        score: float,
        time_ms: int,
        succeeded: bool,
        guard_budget_ok: bool,
        guard_role_ok: bool,
        guard_mode_ok: bool,
    ) -> None:
        self.db.execute_query(
            """
            UPDATE attempts
            SET actions_used = ?, game_actions_used = ?, levels_completed = ?,
                score = ?, time_ms = ?, succeeded = ?,
                guard_budget_ok = ?, guard_role_ok = ?, guard_mode_ok = ?
            WHERE attempt_id = ?
            """,
            (
                actions_used,
                game_actions_used,
                levels_completed,
                score,
                time_ms,
                1 if succeeded else 0,
                1 if guard_budget_ok else 0,
                1 if guard_role_ok else 0,
                1 if guard_mode_ok else 0,
                attempt_id,
            ),
        )

    def record_guard_failure(
        self,
        *,
        attempt_id: str,
        guard_name: str,
        guard_code: str,
        game_id: Optional[str],
        level: Optional[int],
        agent_id: Optional[str],
        generation: Optional[int],
        message: str,
    ) -> None:
        stack_signature = self._stack_hash(f"{guard_name}:{guard_code}:{message}")
        self.db.execute_query(
            """
            INSERT INTO hook_failures (
              attempt_id, hook_name, hook_phase, exception_type, message, stack_hash,
              auto_disabled_flag, game_id, level, agent_id, generation, guard_code
            ) VALUES (?, ?, 'guard', ?, ?, ?, 0, ?, ?, ?, ?, ?)
            """,
            (
                attempt_id,
                guard_name,
                guard_code,
                message,
                stack_signature,
                0,
                game_id,
                level,
                agent_id,
                generation,
                guard_code,
            ),
        )

    def record_hook_failure(
        self,
        *,
        attempt_id: str,
        hook_name: str,
        hook_phase: str,
        message: str,
        game_id: Optional[str] = None,
        level: Optional[int] = None,
        agent_id: Optional[str] = None,
        generation: Optional[int] = None,
        stack_hash: Optional[str] = None,
    ) -> None:
        stack_signature = stack_hash or self._stack_hash(f"{hook_name}:{hook_phase}:{message}")
        self.db.execute_query(
            """
            INSERT INTO hook_failures (
              attempt_id, hook_name, hook_phase, exception_type, message, stack_hash,
              auto_disabled_flag, game_id, level, agent_id, generation, guard_code
            ) VALUES (?, ?, ?, ?, ?, ?, 0, ?, ?, ?, ?, '')
            """,
            (
                attempt_id,
                hook_name,
                hook_phase,
                hook_name,
                message,
                stack_signature,
                game_id,
                level,
                agent_id,
                generation,
            ),
        )

    def log_action_proposal(
        self,
        *,
        attempt_id: str,
        step_idx: int,
        chosen_action: str,
        chosen_reason: str,
        mode: str,
        available_actions: Optional[List[int]] = None,
        proposals: Optional[Dict[str, Any]] = None,
        w_A: Optional[float] = None,
        w_B: Optional[float] = None,
        w_R: Optional[float] = None,
        resonance_tags: Optional[str] = None,
        role_compliance: Optional[str] = None,
        theory_validation_state: Optional[str] = None,
        attention_window_id: Optional[str] = None,
    ) -> None:
        self.db.execute_query(
            """
            INSERT INTO action_proposals_log (
              attempt_id, step_idx, available_actions, proposals, chosen_action,
              chosen_reason, w_A, w_B, w_R, resonance_tags, role_compliance,
              theory_validation_state, attention_window_id, mode
            ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
            """,
            (
                attempt_id,
                step_idx,
                json.dumps(available_actions) if available_actions is not None else None,
                json.dumps(proposals) if proposals else None,
                chosen_action,
                chosen_reason,
                w_A,
                w_B,
                w_R,
                resonance_tags,
                role_compliance,
                theory_validation_state,
                attention_window_id,
                self._validate_mode(mode),
            ),
        )

    def record_replay_pointer(
        self,
        *,
        attempt_id: str,
        scorecard_id: str,
        arc_game_id: str,
        agent_type: str,
        tags_payload: Any = None,
        local_recording_path: Optional[str] = None,
        mode: str = 'LIVE',
    ) -> None:
        """Persist replay_index pointer (thin metadata, no frames)."""
        normalized_mode = self._validate_mode(mode)
        if normalized_mode != 'LIVE':
            return

        try:
            self.db.execute_query(
                """
                INSERT OR IGNORE INTO replay_index (
                  attempt_id, scorecard_id, replay_id, arc_game_id, agent_type, tags, local_recording_path
                ) VALUES (?, ?, NULL, ?, ?, ?, ?)
                """,
                (
                    attempt_id,
                    scorecard_id,
                    arc_game_id,
                    agent_type,
                    json.dumps(tags_payload) if tags_payload is not None else None,
                    local_recording_path,
                ),
            )
        except Exception as err:
            logger.warning(f"Failed to record replay_index for attempt {attempt_id}: {err}")


class GameplayEngine:
    """Core engine for playing ARC games with integrated pattern learning."""

    def __init__(self, api_key: Optional[str] = None, db_path: str = "core_data.db"):
        """Initialize gameplay engine.

        Args:
            api_key: ARC API key
            db_path: Database file path
        """
        self.session_manager: Any = GameSessionManager(api_key, db_path)
        self.action_handler = ActionHandler(self.session_manager)
        self.db: Any = DatabaseInterface(db_path)  # Pattern learning database access
        self.spine_emitter: Any = SpineEmitter(self.db)  # Event spine writer
        self.event_bus = EventBus()
        self.plugin_manager: Optional[PluginManager] = None
        self.event_bus.set_hook_failure_event(EventType.HOOK_FAILURE_DETECTED)
        self.event_bus.subscribe(EventType.HOOK_FAILURE_DETECTED, self._on_hook_failure_event)
        self.prestige_engine = PrestigeEngine(self.db)  # Phase 1: Prestige tracking
        self.sensation_engine = SensationEngine(self.db)  # Phase 4.5: Emotional intelligence
        self.exploration_tracker = NetworkExplorationTracker(self.db)  # Network-level exploration map
        self.budget_allocator = BreakthroughBudgetAllocator(self.db)  # Tier 1: Dynamic budgets
        self.breakthrough_detector = BreakthroughDetector()  # Tier 1: Momentum detection
        self.matching_pipeline = MultiStageMatchingPipeline(self.db)  # Tier 1: Multi-stage matching (+40%)
        self.subgoal_activator = SubgoalPlanningActivator(self.db)  # Tier 1: Subgoal planning (+30%)
        self.agent_self_model = AgentSelfModel(db_path)  # Self-model: Track controlled objects
        self.persona_manager = PersonaManager(self.db)  # Persona submodeling runtime
        self._last_persona_decision = None
        self._last_persona_logged = []
        self._last_observer_flags = {}
        self._last_theory_hint: Dict[str, Any] = {}
        self._last_cods_confidence: Optional[float] = None
        self._last_cods_operator: Optional[str] = None
        self._last_persona_context: Dict[str, Any] = {}
        self._last_goal_info: Optional[Dict[str, Any]] = None
        self._last_ladder_trace: Dict[str, Any] = {}
        self._last_ladder_rung: Optional[str] = None
        self._current_stage: Optional[int] = None
        self.lessons_engine = LessonsLearnedEngine(self.db)
        self.death_hypothesis = DeathCauseHypothesis(self.db)  # Track death causes to learn threat objects
        self.object_detector = ObjectDetector(db_path)  # Object detection for Stream-aware perception
        
        # FIX: Initialize action traces for Q1-Q5 emergent reasoning
        # These traces track frame changes per action for learning what changes vs what's fixed
        self._recent_action_traces = []
        self._recent_actions: List[str] = []
        
        # NOVELTY DETECTOR: Track prediction accuracy to detect novel situations
        # When accuracy drops below threshold, boost wA (trust self over network)
        # This implements fluid adaptation from improvements_for_theory.md
        self._prediction_accuracy_history: List[float] = []  # Rolling window of recent accuracies
        self._novelty_window_size = 20  # Track last N predictions
        self._novelty_threshold = 0.4  # Below this = novel situation
        self._novelty_boost_active = False  # Flag for current novelty state
        self._novelty_wA_boost = 0.2  # How much to boost wA when novel
        
        # I-Thread: The consciousness weaver - manages wA/wB and stream conflict
        # This is the SINGLE SOURCE OF TRUTH for Two Streams consciousness
        # All other systems delegate to IThread for wA/wB management
        self.i_thread = IThread(self.db)
        
        # DeliberationEngine: System 2 reasoning when stuck or novel situations
        # Called when _deliberation_mode_active is True (triggered by extended stuck)
        # Uses conduct_deliberation() for full reasoning chain with Stream A/B consultation
        self.deliberation_engine = DeliberationEngine(self.db)
        self._deliberation_mode_active = False
        self._deliberation_trigger_reason = None
        self._force_strategy_reexamination = False
        self._last_deliberation_result: Optional[DeliberationResult] = None
        
        # Two-Streams: Weaving reporter for self-reflection in every action
        # DELEGATION: WeavingReporter now delegates to IThread for report generation
        self.weaving_reporter = WeavingReporter(self.db, i_thread=self.i_thread)
        
        # Developmental Systems: Cognitive stages and episodic memory
        # DELEGATION: EpisodicMemorySystem delegates wA/wB management to IThread
        self.cognitive_stage_system = CognitiveStageSystem(self.db)
        self.episodic_memory = EpisodicMemorySystem(self.db, i_thread=self.i_thread)
        self.agent_hypothesis_system = AgentHypothesisSystem(self.db, self.cognitive_stage_system)
        
        # Metacognitive Reasoning: Scientific hypothesis testing and theory revision
        # Implements: assumptions, predictions, theory revision, failure analysis, elimination
        self.metacognitive_engine = MetacognitiveReasoningEngine(self.db)

        # Imagination/mental-modeling context (per-step telemetry cache)
